-- Add a reusable 150-sentence situational deck with highlighted vocabulary and audio.
insert into public.template_decks (slug, name, description, level)
values (
  'nha-may-xuong-150-cau',
  'Nhà máy/xưởng - 150 câu',
  '150 câu tiếng Trung theo tình huống nhà máy và xưởng sản xuất: giao ca, vận hành máy, kiểm tra chất lượng, báo lỗi, bảo trì, an toàn lao động và phối hợp sản xuất. Mỗi câu có pinyin, nghĩa tiếng Việt, từ mới được highlight và audio tạo sẵn.',
  'Luyện câu'
)
on conflict (slug) do update
set name = excluded.name, description = excluded.description, level = excluded.level;

with target_deck as (
  select id from public.template_decks where slug = 'nha-may-xuong-150-cau'
)
insert into public.template_sentence_cards (
  template_deck_id, sentence_cn, sentence_pinyin, sentence_vi,
  vocab_json, sentence_audio_url, position
)
select
  target_deck.id, card.sentence_cn, card.sentence_pinyin,
  card.sentence_vi, card.vocab_json::jsonb,
  card.sentence_audio_url, card.position
from target_deck
cross join (
  values
    ('请大家点名，确认今天上班人员到齐了。', 'Qǐng dàjiā diǎnmíng, quèrèn jīntiān shàngbān rényuán dào qí le.', 'Mọi người hãy điểm danh, xác nhận nhân viên ca hôm nay có mặt đầy đủ.', '[{"chinese":"点名","pinyin":"diǎnmíng","meaning_vi":"điểm danh"},{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-253e1ea120d32841dbd07148.mp3', 1),
    ('上一班的生产数量是五千个，已经全部完成。', 'Shàng yī bān de shēngchǎn shùliàng shì wǔ qiān gè, yǐjīng quánbù wánchéng.', 'Sản lượng sản xuất ca trước là năm nghìn sản phẩm, đã hoàn thành hết.', '[{"chinese":"生产数量","pinyin":"shēngchǎn shùliàng","meaning_vi":"sản lượng sản xuất"},{"chinese":"完成","pinyin":"wánchéng","meaning_vi":"hoàn thành"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-90950352c92c4dd65f13487b.mp3', 2),
    ('请检查设备运行状态，有没有异常或故障现象。', 'Qǐng jiǎnchá shèbèi yùnxíng zhuàngtài, yǒu méiyǒu yìcháng huò gùzhàng xiànxiàng.', 'Hãy kiểm tra tình trạng vận hành thiết bị, có bất thường hoặc hỏng hóc gì không.', '[{"chinese":"设备","pinyin":"shèbèi","meaning_vi":"thiết bị"},{"chinese":"运行状态","pinyin":"yùnxíng zhuàngtài","meaning_vi":"tình trạng vận hành"},{"chinese":"异常","pinyin":"yìcháng","meaning_vi":"bất thường"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-346f668842ca70e2fb58b620.mp3', 3),
    ('原料库存充足，今天的订单可以按时完成。', 'Yuánliào kùcún chōngzú, jīntiān de dìngdān kěyǐ ànshí wánchéng.', 'Nguyên liệu trong kho đủ, đơn hàng hôm nay có thể hoàn thành đúng hạn.', '[{"chinese":"原料","pinyin":"yuánliào","meaning_vi":"nguyên liệu"},{"chinese":"库存","pinyin":"kùcún","meaning_vi":"tồn kho"},{"chinese":"订单","pinyin":"dìngdān","meaning_vi":"đơn hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-4d1bad34cce372c0de6f9ea3.mp3', 4),
    ('所有使用的工具都已归位，状态良好。', 'Suǒyǒu shǐyòng de gōngjù dōu yǐ guīwèi, zhuàngtài liánghǎo.', 'Tất cả dụng cụ đã được cất đúng vị trí, trong tình trạng tốt.', '[{"chinese":"工具","pinyin":"gōngjù","meaning_vi":"dụng cụ"},{"chinese":"归位","pinyin":"guīwèi","meaning_vi":"về vị trí"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-967441e1430de56aa88d0943.mp3', 5),
    ('前一班有几个生产异常问题需要解决。', 'Qián yī bān yǒu jǐ gè shēngchǎn yìcháng wèntí xūyào jiějué.', 'Ca trước có vài vấn đề sản xuất bất thường cần giải quyết.', '[{"chinese":"异常","pinyin":"yìcháng","meaning_vi":"bất thường"},{"chinese":"问题","pinyin":"wèntí","meaning_vi":"vấn đề"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-a9d8cf180ca2945302ce90c4.mp3', 6),
    ('请确认接班人员已经了解当前的工作内容。', 'Qǐng quèrèn jiēbān rényuán yǐjīng liǎojiě dāngqián de gōngzuò nèiróng.', 'Xin xác nhận nhân viên tiếp ca đã hiểu rõ nội dung công việc hiện tại.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"接班","pinyin":"jiēbān","meaning_vi":"tiếp ca"},{"chinese":"了解","pinyin":"liǎojiě","meaning_vi":"hiểu rõ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-0aaad374d700728dbe4da9c1.mp3', 7),
    ('今天的生产日志已经填写完毕，请查阅。', 'Jīntiān de shēngchǎn rìzhì yǐjīng tiánxiě wánbì, qǐng cháyuè.', 'Nhật ký sản xuất hôm nay đã hoàn thành, xin vui lòng kiểm tra.', '[{"chinese":"生产日志","pinyin":"shēngchǎn rìzhì","meaning_vi":"nhật ký sản xuất"},{"chinese":"填写","pinyin":"tiánxiě","meaning_vi":"điền, viết vào"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-860e3130df8d3361d5dde695.mp3', 8),
    ('机器运行正常，没有发现异常声音。', 'Jīqì yùnxíng zhèngcháng, méiyǒu fāxiàn yìcháng shēngyīn.', 'Máy móc vận hành bình thường, không phát hiện tiếng động bất thường.', '[{"chinese":"机器","pinyin":"jīqì","meaning_vi":"máy móc"},{"chinese":"异常","pinyin":"yìcháng","meaning_vi":"bất thường"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-ca614391ccbf301345af2b13.mp3', 9),
    ('原材料用量已经核实，库存足够支持生产。', 'Yuáncáiliào yòngliàng yǐjīng héshí, kùcún zúgòu zhīchí shēngchǎn.', 'Lượng nguyên vật liệu đã được kiểm tra, tồn kho đủ để sản xuất.', '[{"chinese":"原材料","pinyin":"yuáncáiliào","meaning_vi":"nguyên vật liệu"},{"chinese":"核实","pinyin":"héshí","meaning_vi":"kiểm tra, xác nhận"},{"chinese":"库存","pinyin":"kùcún","meaning_vi":"tồn kho"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c992ce86d0d3311865949abe.mp3', 10),
    ('生产工具已经整理并摆放整齐。', 'Shēngchǎn gōngjù yǐjīng zhěnglǐ bìng bǎifàng zhěngqí.', 'Dụng cụ sản xuất đã được sắp xếp và đặt ngăn nắp.', '[{"chinese":"工具","pinyin":"gōngjù","meaning_vi":"dụng cụ"},{"chinese":"整理","pinyin":"zhěnglǐ","meaning_vi":"sắp xếp"},{"chinese":"摆放","pinyin":"bǎifàng","meaning_vi":"bày trí"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-05e3195f533875b0bdd70057.mp3', 11),
    ('有几个待处理的问题需要接班人员注意。', 'Yǒu jǐ gè dài chǔlǐ de wèntí xūyào jiēbān rényuán zhùyì.', 'Có vài vấn đề còn tồn đọng cần nhân viên tiếp ca chú ý.', '[{"chinese":"待处理","pinyin":"dài chǔlǐ","meaning_vi":"chờ xử lý, tồn đọng"},{"chinese":"问题","pinyin":"wèntí","meaning_vi":"vấn đề"},{"chinese":"接班","pinyin":"jiēbān","meaning_vi":"tiếp ca"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-b5691713908e3a5699570747.mp3', 12),
    ('请确认所有文件和记录已经交接完毕。', 'Qǐng quèrèn suǒyǒu wénjiàn hé jìlù yǐjīng jiāojiē wánbì.', 'Xin xác nhận tất cả tài liệu và hồ sơ đã được bàn giao xong.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"文件","pinyin":"wénjiàn","meaning_vi":"tài liệu"},{"chinese":"交接","pinyin":"jiāojiē","meaning_vi":"bàn giao"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c4bc3fb9d0f2461d7c0db237.mp3', 13),
    ('本班作业全部完成，可以按时下班。', 'Běn bān zuòyè quánbù wánchéng, kěyǐ ànshí xiàbān.', 'Toàn bộ công việc ca này đã hoàn thành, có thể tan ca đúng giờ.', '[{"chinese":"作业","pinyin":"zuòyè","meaning_vi":"công việc, nhiệm vụ"},{"chinese":"完成","pinyin":"wánchéng","meaning_vi":"hoàn thành"},{"chinese":"按时","pinyin":"ànshí","meaning_vi":"đúng giờ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-3fad1ed1291f7864e63f3c93.mp3', 14),
    ('接班人请仔细检查机器运转情况。', 'Jiēbān rén qǐng zǐxì jiǎnchá jīqì yùnzhuǎn qíngkuàng.', 'Người nhận ca vui lòng kiểm tra kỹ tình trạng vận hành máy móc.', '[{"chinese":"接班人","pinyin":"jiēbān rén","meaning_vi":"người tiếp ca"},{"chinese":"检查","pinyin":"jiǎnchá","meaning_vi":"kiểm tra"},{"chinese":"运转","pinyin":"yùnzhuǎn","meaning_vi":"vận hành"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-fb6c0b781ae04e1014c735af.mp3', 15),
    ('今天的生产计划已交代清楚，请按要求执行。', 'Jīntiān de shēngchǎn jìhuà yǐ jiāodài qīngchǔ, qǐng àn yāoqiú zhíxíng.', 'Kế hoạch sản xuất hôm nay đã được giao rõ, xin thực hiện theo yêu cầu.', '[{"chinese":"生产计划","pinyin":"shēngchǎn jìhuà","meaning_vi":"kế hoạch sản xuất"},{"chinese":"交代","pinyin":"jiāodài","meaning_vi":"giao bài, chỉ đạo"},{"chinese":"执行","pinyin":"zhíxíng","meaning_vi":"thực hiện"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-bbf6c0ae7055c0b37d7138fc.mp3', 16),
    ('请将所有生产设备清洁干净，保持整洁环境。', 'Qǐng jiāng suǒyǒu shēngchǎn shèbèi qīngjié gānjìng, bǎochí zhěngjié huánjìng.', 'Mong mọi người làm sạch toàn bộ thiết bị sản xuất, giữ môi trường gọn gàng.', '[{"chinese":"清洁","pinyin":"qīngjié","meaning_vi":"dọn sạch"},{"chinese":"保持","pinyin":"bǎochí","meaning_vi":"giữ gìn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-bb2fd493f366e5f3c87b9107.mp3', 17),
    ('交接时请详细说明机器的异常情况。', 'Jiāojiē shí qǐng xiángxì shuōmíng jīqì de yìcháng qíngkuàng.', 'Khi bàn giao hãy giải thích chi tiết tình trạng bất thường của máy móc.', '[{"chinese":"交接","pinyin":"jiāojiē","meaning_vi":"bàn giao"},{"chinese":"详细","pinyin":"xiángxì","meaning_vi":"chi tiết"},{"chinese":"异常","pinyin":"yìcháng","meaning_vi":"bất thường"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-1f761bf21aec0a5cc05b74b7.mp3', 18),
    ('请核对产品数量，确保无误后再交接。', 'Qǐng héduì chǎnpǐn shùliàng, quèbǎo wúwù hòu zài jiāojiē.', 'Xin kiểm tra lại số lượng sản phẩm, đảm bảo chính xác rồi mới giao tiếp.', '[{"chinese":"核对","pinyin":"héduì","meaning_vi":"đối chiếu, kiểm tra"},{"chinese":"确保","pinyin":"quèbǎo","meaning_vi":"đảm bảo"},{"chinese":"交接","pinyin":"jiāojiē","meaning_vi":"bàn giao"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-a3754c1e94bc2654f4efb115.mp3', 19),
    ('设备维护记录必须完整，便于后续跟踪。', 'Shèbèi wéihù jìlù bìxū wánzhěng, biànyú hòuxù gēnzōng.', 'Hồ sơ bảo trì thiết bị phải đầy đủ để dễ dàng theo dõi sau này.', '[{"chinese":"维护","pinyin":"wéihù","meaning_vi":"bảo trì, bảo dưỡng"},{"chinese":"记录","pinyin":"jìlù","meaning_vi":"ghi chép, hồ sơ"},{"chinese":"后续","pinyin":"hòuxù","meaning_vi":"sau đó, tiếp tục"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-b38226ca3711fd166c530e4b.mp3', 20),
    ('请确认所有安全防护措施已经到位。', 'Qǐng quèrèn suǒyǒu ānquán fánghù cuòshī yǐjīng dàowèi.', 'Xin xác nhận tất cả biện pháp an toàn đã được thực hiện đầy đủ.', '[{"chinese":"安全防护","pinyin":"ānquán fánghù","meaning_vi":"an toàn bảo hộ"},{"chinese":"措施","pinyin":"cuòshī","meaning_vi":"biện pháp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-1b56845a67b1a6b228e5b567.mp3', 21),
    ('本班的设备调试工作已完成，可以交接。', 'Běn bān de shèbèi tiáoshì gōngzuò yǐ wánchéng, kěyǐ jiāojiē.', 'Công việc điều chỉnh thiết bị của ca này đã xong, có thể bàn giao.', '[{"chinese":"设备调试","pinyin":"shèbèi tiáoshì","meaning_vi":"điều chỉnh thiết bị"},{"chinese":"完成","pinyin":"wánchéng","meaning_vi":"hoàn thành"},{"chinese":"交接","pinyin":"jiāojiē","meaning_vi":"bàn giao"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-36a3465c38eebdeda9114093.mp3', 22),
    ('请核实今天的原料入库数量。', 'Qǐng héshí jīntiān de yuánliào rùkù shùliàng.', 'Xin kiểm tra số lượng nguyên liệu nhập kho hôm nay.', '[{"chinese":"核实","pinyin":"héshí","meaning_vi":"kiểm tra"},{"chinese":"原料","pinyin":"yuánliào","meaning_vi":"nguyên liệu"},{"chinese":"入库","pinyin":"rùkù","meaning_vi":"nhập kho"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-cfa6f1335368b0767f58bf5e.mp3', 23),
    ('本班负责人已将所有事项交代清楚。', 'Běn bān fùzérén yǐ jiāng suǒyǒu shìxiàng jiāodài qīngchǔ.', 'Người chịu trách nhiệm ca này đã giao mọi việc rõ ràng.', '[{"chinese":"负责人","pinyin":"fùzérén","meaning_vi":"người phụ trách"},{"chinese":"事项","pinyin":"shìxiàng","meaning_vi":"các vấn đề, công việc"},{"chinese":"交代","pinyin":"jiāodài","meaning_vi":"đưa ra, giao việc"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-cdca0b552e15db17a4e954ec.mp3', 24),
    ('接班人员如有问题，请及时沟通反馈。', 'Jiēbān rényuán rú yǒu wèntí, qǐng jíshí gōutōng fǎnkuì.', 'Nhân viên nhận ca nếu có vấn đề, vui lòng giao tiếp và phản hồi kịp thời.', '[{"chinese":"接班人员","pinyin":"jiēbān rényuán","meaning_vi":"nhân viên tiếp ca"},{"chinese":"及时","pinyin":"jíshí","meaning_vi":"kịp thời"},{"chinese":"沟通","pinyin":"gōutōng","meaning_vi":"giao tiếp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-2b003d78f5fc085793e791a4.mp3', 25),
    ('开机前请仔细检查设备的电源连接是否稳固。', 'Kāi jī qián qǐng zǐxì jiǎnchá shèbèi de diànyuán liánjiē shìfǒu wěngù.', 'Trước khi khởi động máy, vui lòng kiểm tra kỹ kết nối nguồn điện của thiết bị có chắc chắn không.', '[{"chinese":"检查","pinyin":"jiǎnchá","meaning_vi":"kiểm tra"},{"chinese":"设备","pinyin":"shèbèi","meaning_vi":"thiết bị"},{"chinese":"电源","pinyin":"diànyuán","meaning_vi":"nguồn điện"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-49d711db1767a9cc9a4ef752.mp3', 26),
    ('按操作规程启动机器，确保所有安全装置已激活。', 'Àn cāozuò guīchéng qǐdòng jīqì, quèbǎo suǒyǒu ānquán zhuāngzhì yǐ jīhuó.', 'Khởi động máy theo quy trình vận hành, đảm bảo tất cả thiết bị an toàn đã được kích hoạt.', '[{"chinese":"操作规程","pinyin":"cāozuò guīchéng","meaning_vi":"quy trình vận hành"},{"chinese":"启动","pinyin":"qǐdòng","meaning_vi":"khởi động"},{"chinese":"安全装置","pinyin":"ānquán zhuāngzhì","meaning_vi":"thiết bị an toàn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-2b08d58bdacbde3051315354.mp3', 27),
    ('请按照规定程序停止设备，等待机器完全停转后再操作。', 'Qǐng ànzhào guīdìng chéngxù tíngzhǐ shèbèi, děngdài jīqì wánquán tíng zhuǎn hòu zài cāozuò.', 'Vui lòng dừng thiết bị theo quy trình quy định, chờ máy dừng hoàn toàn rồi mới thao tác.', '[{"chinese":"规定程序","pinyin":"guīdìng chéngxù","meaning_vi":"quy trình quy định"},{"chinese":"停止","pinyin":"tíngzhǐ","meaning_vi":"dừng"},{"chinese":"设备","pinyin":"shèbèi","meaning_vi":"thiết bị"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-7a73cd65c25b93bc36fc3d64.mp3', 28),
    ('请设置温度参数为规定值，确保产品质量稳定。', 'Qǐng shèzhì wēndù cānshù wèi guīdìng zhí, quèbǎo chǎnpǐn zhìliàng wěndìng.', 'Vui lòng cài đặt thông số nhiệt độ theo giá trị quy định để đảm bảo chất lượng sản phẩm ổn định.', '[{"chinese":"设置","pinyin":"shèzhì","meaning_vi":"cài đặt"},{"chinese":"参数","pinyin":"cānshù","meaning_vi":"thông số"},{"chinese":"质量","pinyin":"zhìliàng","meaning_vi":"chất lượng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-970695bdd19d590280b0051b.mp3', 29),
    ('根据订单要求调整机器速度，保证生产效率。', 'Gēnjù dìngdān yāoqiú tiáozhěng jīqì sùdù, bǎozhèng shēngchǎn xiàolǜ.', 'Điều chỉnh tốc độ máy theo yêu cầu đơn hàng để đảm bảo hiệu suất sản xuất.', '[{"chinese":"调整","pinyin":"tiáozhěng","meaning_vi":"điều chỉnh"},{"chinese":"速度","pinyin":"sùdù","meaning_vi":"tốc độ"},{"chinese":"生产效率","pinyin":"shēngchǎn xiàolǜ","meaning_vi":"hiệu suất sản xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-87f0f7eeb854fe3e4e5f8b52.mp3', 30),
    ('请按照使用说明添加原材料，避免机器堵塞。', 'Qǐng ànzhào shǐyòng shuōmíng tiānjiā yuáncáiliào, bìmiǎn jīqì dǔsè.', 'Vui lòng bổ sung nguyên liệu theo hướng dẫn sử dụng để tránh máy bị tắc nghẽn.', '[{"chinese":"原材料","pinyin":"yuáncáiliào","meaning_vi":"nguyên liệu"},{"chinese":"添加","pinyin":"tiānjiā","meaning_vi":"bổ sung"},{"chinese":"堵塞","pinyin":"dǔsè","meaning_vi":"tắc nghẽn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c9b4daf3836f2928b6ee0142.mp3', 31),
    ('操作台上的显示屏实时监控机器运行状态。', 'Cāozuòtái shàng de xiǎnshìpíng shíshí jiānkòng jīqì yùnxíng zhuàngtài.', 'Màn hình hiển thị trên bàn điều khiển giám sát trạng thái vận hành máy theo thời gian thực.', '[{"chinese":"显示屏","pinyin":"xiǎnshìpíng","meaning_vi":"màn hình hiển thị"},{"chinese":"监控","pinyin":"jiānkòng","meaning_vi":"giám sát"},{"chinese":"运行状态","pinyin":"yùnxíng zhuàngtài","meaning_vi":"trạng thái vận hành"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-24f19d382225fb1439c6b658.mp3', 32),
    ('每天作业结束后，必须对设备进行彻底清洁维护。', 'Měitiān zuòyè jiéshù hòu, bìxū duì shèbèi jìnxíng chèdǐ qīngjié wéihù.', 'Sau khi kết thúc sản xuất mỗi ngày, phải tiến hành vệ sinh và bảo trì thiết bị một cách sạch sẽ triệt để.', '[{"chinese":"彻底","pinyin":"chèdǐ","meaning_vi":"triệt để"},{"chinese":"清洁","pinyin":"qīngjié","meaning_vi":"vệ sinh"},{"chinese":"维护","pinyin":"wéihù","meaning_vi":"bảo trì"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-6d7ad2000e52b5061f4e3b9b.mp3', 33),
    ('请填写生产日志，记录机器运行时间和异常情况。', 'Qǐng tiánxiě shēngchǎn rìzhì, jìlù jīqì yùnxíng shíjiān hé yìcháng qíngkuàng.', 'Xin hãy ghi chép nhật ký sản xuất, ghi lại thời gian vận hành máy và các tình huống bất thường.', '[{"chinese":"填写","pinyin":"tiánxiě","meaning_vi":"ghi chép"},{"chinese":"生产日志","pinyin":"shēngchǎn rìzhì","meaning_vi":"nhật ký sản xuất"},{"chinese":"异常","pinyin":"yìcháng","meaning_vi":"bất thường"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-d25ceb91432a4a470002e312.mp3', 34),
    ('启动前确保润滑油充足，减少机器磨损。', 'Qǐdòng qián quèbǎo rùnhuá yóu chōngzú, jiǎnshǎo jīqì mó sǔn.', 'Trước khi khởi động, đảm bảo dầu bôi trơn đầy đủ để giảm hao mòn máy.', '[{"chinese":"润滑油","pinyin":"rùnhuá yóu","meaning_vi":"dầu bôi trơn"},{"chinese":"磨损","pinyin":"mó sǔn","meaning_vi":"hao mòn"},{"chinese":"启动","pinyin":"qǐdòng","meaning_vi":"khởi động"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-fc22b286db310a016417ee19.mp3', 35),
    ('操作时请佩戴防护手套，预防机械伤害。', 'Cāozuò shí qǐng pèidài fánghù shǒutào, yùfáng jīxiè shānghài.', 'Khi vận hành vui lòng đeo găng tay bảo hộ để phòng tránh thương tích do máy móc.', '[{"chinese":"防护手套","pinyin":"fánghù shǒutào","meaning_vi":"găng tay bảo hộ"},{"chinese":"机械伤害","pinyin":"jīxiè shānghài","meaning_vi":"thương tích do máy móc"},{"chinese":"操作","pinyin":"cāozuò","meaning_vi":"vận hành"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-d4c8678465721a2774acfb30.mp3', 36),
    ('暂停生产时，应先关闭物料输送系统。', 'Zàntíng shēngchǎn shí, yīng xiān guānbì wùliào shūsòng xìtǒng.', 'Khi tạm dừng sản xuất, trước hết phải tắt hệ thống băng tải nguyên liệu.', '[{"chinese":"暂停","pinyin":"zàntíng","meaning_vi":"tạm dừng"},{"chinese":"物料输送系统","pinyin":"wùliào shūsòng xìtǒng","meaning_vi":"hệ thống băng tải nguyên liệu"},{"chinese":"关闭","pinyin":"guānbì","meaning_vi":"tắt"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-fd484e8d3db00e50fcc23f3c.mp3', 37),
    ('调整机器转速时，请缓慢旋转控制旋钮。', 'Tiáozhěng jīqì zhuǎnsù shí, qǐng huǎnmàn xuánzhuǎn kòngzhì xuánniǔ.', 'Khi điều chỉnh tốc độ quay của máy, vui lòng xoay núm điều khiển một cách từ từ.', '[{"chinese":"调整","pinyin":"tiáozhěng","meaning_vi":"điều chỉnh"},{"chinese":"转速","pinyin":"zhuǎnsù","meaning_vi":"tốc độ quay"},{"chinese":"旋钮","pinyin":"xuánniǔ","meaning_vi":"nút điều khiển"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-9ee1491fd527fc531699133f.mp3', 38),
    ('每天开机前必须检查润滑系统是否正常工作。', 'Měitiān kāijī qián bìxū jiǎnchá rùnhuá xìtǒng shìfǒu zhèngcháng gōngzuò.', 'Mỗi ngày trước khi khởi động máy phải kiểm tra xem hệ thống bôi trơn có hoạt động bình thường không.', '[{"chinese":"润滑系统","pinyin":"rùnhuá xìtǒng","meaning_vi":"hệ thống bôi trơn"},{"chinese":"检查","pinyin":"jiǎnchá","meaning_vi":"kiểm tra"},{"chinese":"正常工作","pinyin":"zhèngcháng gōngzuò","meaning_vi":"làm việc bình thường"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-96562650f0e119d1d595f459.mp3', 39),
    ('如发现设备异常，请立即停止运行并报告技术员。', 'Rú fāxiàn shèbèi yìcháng, qǐng lìjí tíngzhǐ yùnxíng bìng bàogào jìshù yuán.', 'Nếu phát hiện thiết bị có bất thường, hãy dừng vận hành ngay lập tức và báo cáo kỹ thuật viên.', '[{"chinese":"设备异常","pinyin":"shèbèi yìcháng","meaning_vi":"thiết bị bất thường"},{"chinese":"停止运行","pinyin":"tíngzhǐ yùnxíng","meaning_vi":"dừng vận hành"},{"chinese":"技术员","pinyin":"jìshù yuán","meaning_vi":"kỹ thuật viên"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-0e3dcd42dbd43065a96db355.mp3', 40),
    ('更换模具之前请关闭机器电源，防止意外启动。', 'Gēnghuàn mújù zhīqián qǐng guānbì jīqì diànyuán, fángzhǐ yìwài qǐdòng.', 'Trước khi thay khuôn hãy tắt nguồn máy để tránh khởi động ngoài ý muốn.', '[{"chinese":"防止","pinyin":"fángzhǐ","meaning_vi":"phòng ngừa"},{"chinese":"意外启动","pinyin":"yìwài qǐdòng","meaning_vi":"khởi động ngoài ý muốn"},{"chinese":"关闭","pinyin":"guānbì","meaning_vi":"tắt"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-e7544823201060d45042a113.mp3', 41),
    ('请定期检查设备的传感器，确保检测准确。', 'Qǐng dìngqī jiǎnchá shèbèi de chuángǎnqì, quèbǎo jiǎncè zhǔnquè.', 'Vui lòng kiểm tra cảm biến thiết bị định kỳ để đảm bảo phát hiện chính xác.', '[{"chinese":"定期","pinyin":"dìngqī","meaning_vi":"định kỳ"},{"chinese":"传感器","pinyin":"chuángǎnqì","meaning_vi":"cảm biến"},{"chinese":"检测","pinyin":"jiǎncè","meaning_vi":"phát hiện, kiểm tra"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-ee361ee7b782330464ac3656.mp3', 42),
    ('设备出现异常时，应立即停止生产并通知维修人员。', 'Shèbèi chūxiàn yìcháng shí, yīng lìjí tíngzhǐ shēngchǎn bìng tōngzhī wéixiū rényuán.', 'Khi thiết bị xảy ra bất thường, nên ngừng sản xuất ngay lập tức và thông báo cho nhân viên bảo trì.', '[{"chinese":"维修人员","pinyin":"wéixiū rényuán","meaning_vi":"nhân viên bảo trì"},{"chinese":"异常","pinyin":"yìcháng","meaning_vi":"bất thường"},{"chinese":"停止生产","pinyin":"tíngzhǐ shēngchǎn","meaning_vi":"dừng sản xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-afd6a6efa1debc234ca0231c.mp3', 43),
    ('更换滤芯后请检查密封是否完好，防止泄漏。', 'Gēnghuàn lǜxīn hòu qǐng jiǎnchá mìfēng shìfǒu wánhǎo, fángzhǐ xièlòu.', 'Sau khi thay lõi lọc, hãy kiểm tra xem phần bịt kín có còn nguyên vẹn không để tránh rò rỉ.', '[{"chinese":"滤芯","pinyin":"lǜxīn","meaning_vi":"lõi lọc"},{"chinese":"密封","pinyin":"mìfēng","meaning_vi":"bịt kín"},{"chinese":"泄漏","pinyin":"xièlòu","meaning_vi":"rò rỉ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-fd807a5e0328a330c56d5b18.mp3', 44),
    ('操作期间请密切观察仪表，及时发现异常数据。', 'Cāozuò qījiān qǐng mìqiè guānchá yíbiǎo, jíshí fāxiàn yìcháng shùjù.', 'Trong quá trình vận hành, xin quan sát sát biểu đồ và dữ liệu để kịp thời phát hiện các số liệu bất thường.', '[{"chinese":"观察","pinyin":"guānchá","meaning_vi":"quan sát"},{"chinese":"仪表","pinyin":"yíbiǎo","meaning_vi":"biểu đồ, thiết bị đo"},{"chinese":"异常","pinyin":"yìcháng","meaning_vi":"bất thường"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c2081376892d1e6f350bb17b.mp3', 45),
    ('机器出现异常声音时，应立即停止并检查内部故障。', 'Jīqì chūxiàn yìcháng shēngyīn shí, yīng lìjí tíngzhǐ bìng jiǎnchá nèibù gùzhàng.', 'Khi máy có tiếng động bất thường, cần dừng ngay và kiểm tra sự cố bên trong.', '[{"chinese":"异常声音","pinyin":"yìcháng shēngyīn","meaning_vi":"tiếng ồn bất thường"},{"chinese":"停止","pinyin":"tíngzhǐ","meaning_vi":"dừng"},{"chinese":"故障","pinyin":"gùzhàng","meaning_vi":"sự cố"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-0ece74bb671f85db74539f84.mp3', 46),
    ('每日工作前请仔细检查所有传动部件的润滑情况。', 'Měi rì gōngzuò qián qǐng zǐxì jiǎnchá suǒyǒu chuán dòng bùjiàn de rùnhuá qíngkuàng.', 'Mỗi ngày trước khi làm việc hãy kiểm tra kỹ tình trạng bôi trơn tất cả các linh kiện truyền động.', '[{"chinese":"传动部件","pinyin":"chuán dòng bùjiàn","meaning_vi":"linh kiện truyền động"},{"chinese":"润滑","pinyin":"rùnhuá","meaning_vi":"bôi trơn"},{"chinese":"检查","pinyin":"jiǎnchá","meaning_vi":"kiểm tra"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-d2b7e7a424f8f547868288f3.mp3', 47),
    ('每班结束后请记录设备运行时间和使用状况。', 'Měi bān jiéshù hòu qǐng jìlù shèbèi yùnxíng shíjiān hé shǐyòng zhuàngkuàng.', 'Sau mỗi ca làm việc vui lòng ghi chép thời gian vận hành thiết bị và tình trạng sử dụng.', '[{"chinese":"每班","pinyin":"měi bān","meaning_vi":"mỗi ca"},{"chinese":"记录","pinyin":"jìlù","meaning_vi":"ghi chép"},{"chinese":"使用状况","pinyin":"shǐyòng zhuàngkuàng","meaning_vi":"tình trạng sử dụng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c4e5d5c044f04e499618d517.mp3', 48),
    ('设备长期停机后必须先进行全面检查再重新启动。', 'Shèbèi chángqí tíngjī hòu bìxū xiān jìnxíng quánmiàn jiǎnchá zài chóngxīn qǐdòng.', 'Sau khi thiết bị ngừng hoạt động lâu dài phải kiểm tra toàn diện trước khi khởi động lại.', '[{"chinese":"长期","pinyin":"chángqí","meaning_vi":"lâu dài"},{"chinese":"停机","pinyin":"tíngjī","meaning_vi":"dừng máy"},{"chinese":"全面检查","pinyin":"quánmiàn jiǎnchá","meaning_vi":"kiểm tra toàn diện"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-30d64cbeba5ce7293e70ee54.mp3', 49),
    ('加注润滑油时应避免过量，防止污染产品。', 'Jiāzhù rùnhuá yóu shí yīng bìmiǎn guòliàng, fángzhǐ wūrǎn chǎnpǐn.', 'Khi bổ sung dầu bôi trơn cần tránh quá nhiều để phòng ngừa làm bẩn sản phẩm.', '[{"chinese":"加注","pinyin":"jiāzhù","meaning_vi":"bổ sung"},{"chinese":"过量","pinyin":"guòliàng","meaning_vi":"quá mức"},{"chinese":"污染","pinyin":"wūrǎn","meaning_vi":"ô nhiễm"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-f4f0c421f6c07721c9a312f7.mp3', 50),
    ('请在生产线上随机抽取样品进行质量检测。', 'Qǐng zài shēngchǎn xiàn shùnjī tiāoqǔ yàngpǐn jìnxíng zhìliàng jiǎncè.', 'Vui lòng lấy mẫu ngẫu nhiên trên dây chuyền sản xuất để kiểm tra chất lượng.', '[{"chinese":"随机抽取","pinyin":"suíjī chōuqǔ","meaning_vi":"lấy mẫu ngẫu nhiên"},{"chinese":"质量检测","pinyin":"zhìliàng jiǎncè","meaning_vi":"kiểm tra chất lượng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-e9403e551a360feb63487539.mp3', 51),
    ('请用卡尺测量产品的长度和宽度，确保尺寸合格。', 'Qǐng yòng kǎchǐ cèliáng chǎnpǐn de chángdù hé kuāndù, quèbǎo chǐcùn hégé.', 'Vui lòng dùng thước cặp đo chiều dài và chiều rộng sản phẩm để đảm bảo kích thước đạt chuẩn.', '[{"chinese":"卡尺","pinyin":"kǎchǐ","meaning_vi":"thước cặp"},{"chinese":"尺寸合格","pinyin":"chǐcùn hégé","meaning_vi":"kích thước đạt chuẩn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-5c7a48bf3d8d7d67a2f3536f.mp3', 52),
    ('对照标准手册检查产品外观是否存在划痕或变形。', 'Duìzhào biāozhǔn shǒucè jiǎnchá chǎnpǐn wàiguān shìfǒu cúnzài huáhén huò biànxíng.', 'Đối chiếu với sổ tay tiêu chuẩn để kiểm tra sản phẩm có bị trầy xước hoặc biến dạng không.', '[{"chinese":"对照标准","pinyin":"duìzhào biāozhǔn","meaning_vi":"đối chiếu tiêu chuẩn"},{"chinese":"划痕","pinyin":"huáhén","meaning_vi":"vết trầy xước"},{"chinese":"变形","pinyin":"biànxíng","meaning_vi":"biến dạng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-fdab04b78120b14215568c00.mp3', 53),
    ('请将检测不合格的产品放入隔离区，避免混入良品。', 'Qǐng jiāng jiǎncè bù hégé de chǎnpǐn fàng rù gélí qū, bìmiǎn hùn rù liángpǐn.', 'Vui lòng cách ly sản phẩm không đạt kiểm tra vào khu vực cách ly để tránh lẫn vào hàng tốt.', '[{"chinese":"检测不合格","pinyin":"jiǎncè bù hégé","meaning_vi":"kiểm tra không đạt"},{"chinese":"隔离区","pinyin":"gélí qū","meaning_vi":"khu vực cách ly"},{"chinese":"良品","pinyin":"liángpǐn","meaning_vi":"hàng tốt"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-ec924f5c66e4d861a222775f.mp3', 54),
    ('填写质量检验报告，详细记录检测结果和发现的问题。', 'Tiánxiě zhìliàng jiǎnyàn bàogào, xiángxì jìlù jiǎncè jiéguǒ hé fāxiàn de wèntí.', 'Điền báo cáo kiểm tra chất lượng, ghi chép chi tiết kết quả và các vấn đề phát hiện được.', '[{"chinese":"质量检验报告","pinyin":"zhìliàng jiǎnyàn bàogào","meaning_vi":"báo cáo kiểm tra chất lượng"},{"chinese":"详细记录","pinyin":"xiángxì jìlù","meaning_vi":"ghi chép chi tiết"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-8ee080dda80c5035c465b254.mp3', 55),
    ('确认产品尺寸符合图纸要求后，方可进行下一道工序。', 'Quèrèn chǎnpǐn chǐcùn fúhé túzhǐ yāoqiú hòu, fāngkě jìnxíng xià yī dào gōngxù.', 'Xác nhận kích thước sản phẩm phù hợp bản vẽ trước khi thực hiện công đoạn tiếp theo.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"符合","pinyin":"fúhé","meaning_vi":"phù hợp"},{"chinese":"工序","pinyin":"gōngxù","meaning_vi":"công đoạn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-6a7c9dac83d884ee0d601577.mp3', 56),
    ('如发现表面有油污，请立即通知清洁人员处理。', 'Rú fāxiàn biǎomiàn yǒu yóuwū, qǐng lìjí tōngzhī qīngjié rényuán chǔlǐ.', 'Nếu phát hiện bề mặt có dầu nhớt, vui lòng báo ngay nhân viên vệ sinh xử lý.', '[{"chinese":"表面","pinyin":"biǎomiàn","meaning_vi":"bề mặt"},{"chinese":"油污","pinyin":"yóuwū","meaning_vi":"dầu nhớt bẩn"},{"chinese":"清洁人员","pinyin":"qīngjié rényuán","meaning_vi":"nhân viên vệ sinh"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-2dbe6a07da1635eb15596410.mp3', 57),
    ('请对照质量标准，判断产品是否达到出货要求。', 'Qǐng duìzhào zhìliàng biāozhǔn, pànduàn chǎnpǐn shìfǒu dádào chū huò yāoqiú.', 'Vui lòng đối chiếu tiêu chuẩn chất lượng để đánh giá sản phẩm có đạt yêu cầu xuất hàng không.', '[{"chinese":"质量标准","pinyin":"zhìliàng biāozhǔn","meaning_vi":"tiêu chuẩn chất lượng"},{"chinese":"出货要求","pinyin":"chū huò yāoqiú","meaning_vi":"yêu cầu xuất hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-2dd8a4f2d636c05ed4cdaa92.mp3', 58),
    ('在检验过程中，如发现异常，应立即暂停检测并报告。', 'Zài jiǎnyàn guòchéng zhōng, rú fāxiàn yìcháng, yīng lìjí zàntíng jiǎncè bìng bàogào.', 'Trong quá trình kiểm tra, nếu phát hiện bất thường, nên tạm dừng kiểm tra và báo cáo ngay lập tức.', '[{"chinese":"检验过程","pinyin":"jiǎnyàn guòchéng","meaning_vi":"quá trình kiểm tra"},{"chinese":"异常","pinyin":"yìcháng","meaning_vi":"bất thường"},{"chinese":"暂停检测","pinyin":"zàntíng jiǎncè","meaning_vi":"tạm dừng kiểm tra"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-e643c6ef4fcc53c03201cdea.mp3', 59),
    ('所有不合格品必须标识清楚，方便后续处理。', 'Suǒyǒu bù hégé pǐn bìxū biāoshí qīngchǔ, fāngbiàn hòuxù chǔlǐ.', 'Tất cả hàng không đạt phải được đánh dấu rõ ràng để thuận tiện xử lý sau đó.', '[{"chinese":"不合格品","pinyin":"bù hégé pǐn","meaning_vi":"hàng không đạt"},{"chinese":"标识清楚","pinyin":"biāoshí qīngchǔ","meaning_vi":"đánh dấu rõ ràng"},{"chinese":"后续处理","pinyin":"hòuxù chǔlǐ","meaning_vi":"xử lý sau đó"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-09931e880adb6bb60ec20ba9.mp3', 60),
    ('请技术员复检有争议的样品，确保数据准确。', 'Qǐng jìshùyuán fù jiǎn yǒu zhēngyì de yàngpǐn, quèbǎo shùjù zhǔnquè.', 'Yêu cầu kỹ thuật viên kiểm tra lại mẫu có tranh chấp, đảm bảo số liệu chính xác.', '[{"chinese":"技术员","pinyin":"jìshùyuán","meaning_vi":"kỹ thuật viên"},{"chinese":"复检","pinyin":"fù jiǎn","meaning_vi":"kiểm tra lại"},{"chinese":"争议","pinyin":"zhēngyì","meaning_vi":"tranh chấp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-de23beb0f22ca6ab21f3abec.mp3', 61),
    ('确认所有检验记录填写完整，便于追溯和管理。', 'Quèrèn suǒyǒu jiǎnyàn jìlù tiánxiě wánzhěng, biànyú zhuīsù hé guǎnlǐ.', 'Xác nhận tất cả phiếu kiểm tra được điền đầy đủ để thuận tiện cho truy xuất và quản lý.', '[{"chinese":"检验记录","pinyin":"jiǎnyàn jìlù","meaning_vi":"phiếu kiểm tra"},{"chinese":"填写完整","pinyin":"tiánxiě wánzhěng","meaning_vi":"điền đầy đủ"},{"chinese":"追溯","pinyin":"zhuīsù","meaning_vi":"truy xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-3c1aa4d2d7c325f0e9926e9a.mp3', 62),
    ('产品包装前，请再次核对尺寸和外观质量。', 'Chǎnpǐn bāozhuāng qián, qǐng zàicì héduì chǐcùn hé wàiguān zhìliàng.', 'Trước khi đóng gói sản phẩm, vui lòng kiểm tra lại kích thước và chất lượng ngoại quan.', '[{"chinese":"包装","pinyin":"bāozhuāng","meaning_vi":"đóng gói"},{"chinese":"核对","pinyin":"héduì","meaning_vi":"kiểm tra"},{"chinese":"外观质量","pinyin":"wàiguān zhìliàng","meaning_vi":"chất lượng ngoại quan"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-42f91b396eeb3502e72daea0.mp3', 63),
    ('发现产品颜色不均匀，应及时反馈并处理。', 'Fāxiàn chǎnpǐn yánsè bù jūnyún, yīng jíshí fǎnkuì bìng chǔlǐ.', 'Phát hiện sản phẩm có màu sắc không đều, cần phản hồi và xử lý kịp thời.', '[{"chinese":"颜色不均匀","pinyin":"yánsè bù jūnyún","meaning_vi":"màu sắc không đều"},{"chinese":"及时反馈","pinyin":"jíshí fǎnkuì","meaning_vi":"phản hồi kịp thời"},{"chinese":"处理","pinyin":"chǔlǐ","meaning_vi":"xử lý"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-2746aa0ed1173fb9f9f95177.mp3', 64),
    ('请按照标准操作程序进行样品采集，确保数据代表性。', 'Qǐng ànzhào biāozhǔn cāozuò chéngxù jìnxíng yàngpǐn cǎijí, quèbǎo shùjù dàibiǎo xìng.', 'Vui lòng tiến hành lấy mẫu theo quy trình tiêu chuẩn để đảm bảo dữ liệu có tính đại diện.', '[{"chinese":"标准操作程序","pinyin":"biāozhǔn cāozuò chéngxù","meaning_vi":"quy trình thao tác tiêu chuẩn"},{"chinese":"样品采集","pinyin":"yàngpǐn cǎijí","meaning_vi":"lấy mẫu"},{"chinese":"代表性","pinyin":"dàibiǎo xìng","meaning_vi":"tính đại diện"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-1bff2a7a23264a399f05b123.mp3', 65),
    ('请记录检测时间和检测人员，以便后续跟踪。', 'Qǐng jìlù jiǎncè shíjiān hé jiǎncè rényuán, yǐbiàn hòuxù gēnzōng.', 'Vui lòng ghi lại thời gian kiểm tra và nhân viên kiểm tra để thuận tiện quản lý sau này.', '[{"chinese":"检测时间","pinyin":"jiǎncè shíjiān","meaning_vi":"thời gian kiểm tra"},{"chinese":"检测人员","pinyin":"jiǎncè rényuán","meaning_vi":"nhân viên kiểm tra"},{"chinese":"跟踪","pinyin":"gēnzōng","meaning_vi":"theo dõi quản lý"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c0be732475bc25ce7633302f.mp3', 66),
    ('确认批次标签粘贴正确，避免混淆不同批次产品。', 'Quèrèn pīcì biāoqiān zhāntiē zhèngquè, bìmiǎn hùnxiáo bùtóng pīcì chǎnpǐn.', 'Xác nhận nhãn mác của lô hàng được dán đúng để tránh nhầm lẫn sản phẩm các lô khác nhau.', '[{"chinese":"批次标签","pinyin":"pīcì biāoqiān","meaning_vi":"nhãn lô hàng"},{"chinese":"粘贴","pinyin":"zhāntiē","meaning_vi":"dán"},{"chinese":"混淆","pinyin":"hùnxiáo","meaning_vi":"nhầm lẫn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c928d4613aca80589ea627c6.mp3', 67),
    ('检测过程中请保持环境清洁，防止样品污染。', 'Jiǎncè guòchéng zhōng qǐng bǎochí huánjìng qīngjié, fángzhǐ yàngpǐn wūrǎn.', 'Trong quá trình kiểm tra, vui lòng giữ môi trường sạch sẽ để tránh mẫu bị nhiễm bẩn.', '[{"chinese":"检测过程","pinyin":"jiǎncè guòchéng","meaning_vi":"quá trình kiểm tra"},{"chinese":"环境清洁","pinyin":"huánjìng qīngjié","meaning_vi":"môi trường sạch sẽ"},{"chinese":"污染","pinyin":"wūrǎn","meaning_vi":"ô nhiễm, nhiễm bẩn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-131e994137b2b5faf655675b.mp3', 68),
    ('发现包装破损产品，请及时作标识并隔离。', 'Fāxiàn bāozhuāng pòsǔn chǎnpǐn, qǐng jíshí zuò biāoshí bìng gélí.', 'Phát hiện sản phẩm bị hư hỏng bao bì, vui lòng đánh dấu và cách ly kịp thời.', '[{"chinese":"包装破损","pinyin":"bāozhuāng pòsǔn","meaning_vi":"bao bì hư hỏng"},{"chinese":"作标识","pinyin":"zuò biāoshí","meaning_vi":"đánh dấu"},{"chinese":"隔离","pinyin":"gélí","meaning_vi":"cách ly"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-fb6fda526aa2aab203f11c9d.mp3', 69),
    ('需要二次检验的产品，请标记并通知质检部门。', 'Xūyào èr cì jiǎnyàn de chǎnpǐn, qǐng biāojì bìng tōngzhī zhìjiǎn bùmén.', 'Sản phẩm cần kiểm tra lần hai, vui lòng đánh dấu và thông báo cho phòng kiểm chất lượng.', '[{"chinese":"二次检验","pinyin":"èr cì jiǎnyàn","meaning_vi":"kiểm tra lần hai"},{"chinese":"标记","pinyin":"biāojì","meaning_vi":"đánh dấu"},{"chinese":"质检部门","pinyin":"zhìjiǎn bùmén","meaning_vi":"phòng kiểm chất lượng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-ca90764d4fa126adecab89bd.mp3', 70),
    ('测量结果如有异常，请重新校准测量工具。', 'Cèliáng jiéguǒ rú yǒu yìcháng, qǐng chóngxīn jiàozhǔn cèliáng gōngjù.', 'Nếu kết quả đo có bất thường, vui lòng hiệu chuẩn lại dụng cụ đo.', '[{"chinese":"测量结果","pinyin":"cèliáng jiéguǒ","meaning_vi":"kết quả đo"},{"chinese":"异常","pinyin":"yìcháng","meaning_vi":"bất thường"},{"chinese":"校准","pinyin":"jiàozhǔn","meaning_vi":"hiệu chuẩn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-f4c0dec977f9b7b292807263.mp3', 71),
    ('为保证检测准确，请严格按照操作规程执行。', 'Wèi bǎozhèng jiǎncè zhǔnquè, qǐng yángé ànzhào cāozuò guīchéng zhíxíng.', 'Để đảm bảo kiểm tra chuẩn xác, vui lòng thực hiện nghiêm túc theo quy trình làm việc.', '[{"chinese":"保证","pinyin":"bǎozhèng","meaning_vi":"đảm bảo"},{"chinese":"操作规程","pinyin":"cāozuò guīchéng","meaning_vi":"quy trình làm việc"},{"chinese":"执行","pinyin":"zhíxíng","meaning_vi":"thực hiện"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-106bf3659e396dad0a946dd4.mp3', 72),
    ('对不合格品进行详细分类，方便后续处理和分析。', 'Duì bù hégé pǐn jìnxíng xiángxì fēnlèi, fāngbiàn hòuxù chǔlǐ hé fēnxī.', 'Phân loại chi tiết các sản phẩm không đạt, thuận tiện cho xử lý và phân tích sau này.', '[{"chinese":"不合格品","pinyin":"bù hégé pǐn","meaning_vi":"hàng không đạt"},{"chinese":"详细分类","pinyin":"xiángxì fēnlèi","meaning_vi":"phân loại chi tiết"},{"chinese":"分析","pinyin":"fēnxī","meaning_vi":"phân tích"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-33556597752f25e9591c6f21.mp3', 73),
    ('质量异常报告必须及时上报，避免影响生产进度。', 'Zhìliàng yìcháng bàogào bìxū jíshí shàngbào, bìmiǎn yǐngxiǎng shēngchǎn jìndù.', 'Báo cáo chất lượng bất thường phải được gửi lên kịp thời để tránh ảnh hưởng tiến độ sản xuất.', '[{"chinese":"质量异常","pinyin":"zhìliàng yìcháng","meaning_vi":"bất thường chất lượng"},{"chinese":"及时上报","pinyin":"jíshí shàngbào","meaning_vi":"gửi báo cáo kịp thời"},{"chinese":"生产进度","pinyin":"shēngchǎn jìndù","meaning_vi":"tiến độ sản xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-19e91ad063909e5e49924997.mp3', 74),
    ('出货前请再次确认所有产品均符合客户要求。', 'Chū huò qián qǐng zàicì quèrèn suǒyǒu chǎnpǐn jūn fúhé kèhù yāoqiú.', 'Trước khi xuất hàng, vui lòng xác nhận lần cuối tất cả sản phẩm đều đáp ứng yêu cầu khách hàng.', '[{"chinese":"出货","pinyin":"chū huò","meaning_vi":"xuất hàng"},{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"客户要求","pinyin":"kèhù yāoqiú","meaning_vi":"yêu cầu khách hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-e889b16a549ad50afad36f4f.mp3', 75),
    ('操作时发现设备运行声音异常，请立即停机检查原因。', 'Cāozuò shí fāxiàn shèbèi yùnxíng shēngyīn yìcháng, qǐng lìjí tíngjī jiǎnchá yuányīn.', 'Khi vận hành phát hiện tiếng thiết bị hoạt động bất thường, hãy dừng máy ngay để kiểm tra nguyên nhân.', '[{"chinese":"设备","pinyin":"shèbèi","meaning_vi":"thiết bị"},{"chinese":"声音异常","pinyin":"shēngyīn yìcháng","meaning_vi":"tiếng động bất thường"},{"chinese":"停机","pinyin":"tíngjī","meaning_vi":"dừng máy"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-658f165240b54afef17608b3.mp3', 76),
    ('机器运行时温度过高，超过安全范围，请马上通知技术人员。', 'Jīqì yùnxíng shí wēndù guò gāo, chāoguò ānquán fànwéi, qǐng mǎshàng tōngzhī jìshù rényuán.', 'Khi máy chạy nhiệt độ quá cao, vượt quá phạm vi an toàn, hãy ngay lập tức báo nhân viên kỹ thuật.', '[{"chinese":"温度过高","pinyin":"wēndù guò gāo","meaning_vi":"nhiệt độ quá cao"},{"chinese":"安全范围","pinyin":"ānquán fànwéi","meaning_vi":"phạm vi an toàn"},{"chinese":"通知","pinyin":"tōngzhī","meaning_vi":"thông báo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-6a01d8fed707643c175bbdfc.mp3', 77),
    ('观察到设备震动异常剧烈，可能存在机械故障，请立即停机。', 'Guānchá dào shèbèi zhèndòng yìcháng jùliè, kěnéng cúnzài jīxiè gùzhàng, qǐng lìjí tíngjī.', 'Quan sát thấy thiết bị rung động bất thường mạnh, có thể có sự cố cơ khí, hãy dừng máy ngay.', '[{"chinese":"震动异常","pinyin":"zhèndòng yìcháng","meaning_vi":"rung động bất thường"},{"chinese":"机械故障","pinyin":"jīxiè gùzhàng","meaning_vi":"sự cố cơ khí"},{"chinese":"停机","pinyin":"tíngjī","meaning_vi":"dừng máy"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-85ff0d45c51013ba9b8f79af.mp3', 78),
    ('发现机械部件损坏，需要更换对应零件方可继续运行。', 'Fāxiàn jīxiè bùjiàn sǔnhuài, xūyào gēnghuàn duìyìng língjiàn fāngkě jìxù yùnxíng.', 'Phát hiện bộ phận máy móc bị hỏng, cần thay linh kiện tương ứng mới có thể tiếp tục vận hành.', '[{"chinese":"机械部件","pinyin":"jīxiè bùjiàn","meaning_vi":"bộ phận máy móc"},{"chinese":"更换","pinyin":"gēnghuàn","meaning_vi":"thay thế"},{"chinese":"零件","pinyin":"língjiàn","meaning_vi":"linh kiện"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-2bdd8b5d01244a07236fe89c.mp3', 79),
    ('机器出现E12故障代码，可能是传感器信号异常导致。', 'Jīqì chūxiàn E12 gùzhàng dàimǎ, kěnéng shì chuángǎnqì xìnhào yìcháng dǎozhì.', 'Máy xuất hiện mã lỗi E12, có thể do tín hiệu cảm biến bị bất thường gây ra.', '[{"chinese":"故障代码","pinyin":"gùzhàng dàimǎ","meaning_vi":"mã lỗi"},{"chinese":"传感器","pinyin":"chuángǎnqì","meaning_vi":"cảm biến"},{"chinese":"信号异常","pinyin":"xìnhào yìcháng","meaning_vi":"tín hiệu bất thường"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-65f2ec0a66629f37ba45ce4f.mp3', 80),
    ('执行设备维护时，请关闭电源并张贴维修标识，确保安全。', 'Zhíxíng shèbèi wéihù shí, qǐng guānbì diànyuán bìng zhāngtiē wéixiū biāoshí, quèbǎo ānquán.', 'Khi thực hiện bảo trì thiết bị, hãy tắt nguồn điện và dán nhãn bảo trì để đảm bảo an toàn.', '[{"chinese":"设备维护","pinyin":"shèbèi wéihù","meaning_vi":"bảo trì thiết bị"},{"chinese":"关闭电源","pinyin":"guānbì diànyuán","meaning_vi":"tắt nguồn điện"},{"chinese":"维修标识","pinyin":"wéixiū biāoshí","meaning_vi":"nhãn bảo trì"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-179b173e22425ae971551f79.mp3', 81),
    ('更换轴承后，请按标准程序进行设备试运行。', 'Gēnghuàn zhóuchéng hòu, qǐng àn biāozhǔn chéngxù jìnxíng shèbèi shì yùnxíng.', 'Sau khi thay vòng bi, hãy thực hiện chạy thử thiết bị theo quy trình tiêu chuẩn.', '[{"chinese":"更换","pinyin":"gēnghuàn","meaning_vi":"thay thế"},{"chinese":"轴承","pinyin":"zhóuchéng","meaning_vi":"vòng bi"},{"chinese":"试运行","pinyin":"shì yùnxíng","meaning_vi":"chạy thử"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-2b06b78a53692bb36f707903.mp3', 82),
    ('定期检查润滑系统，确保设备运转顺畅无卡顿。', 'Dìngqī jiǎnchá rùnhuá xìtǒng, quèbǎo shèbèi yùnzhuǎn shùnchàng wú kǎdùn.', 'Kiểm tra định kỳ hệ thống bôi trơn, đảm bảo thiết bị vận hành trơn tru không bị kẹt.', '[{"chinese":"定期检查","pinyin":"dìngqī jiǎnchá","meaning_vi":"kiểm tra định kỳ"},{"chinese":"润滑系统","pinyin":"rùnhuá xìtǒng","meaning_vi":"hệ thống bôi trơn"},{"chinese":"无卡顿","pinyin":"wú kǎdùn","meaning_vi":"không bị kẹt"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-3932d7005f7d8d7f9f233c6c.mp3', 83),
    ('设备突然停机，请检查电源是否断开并报告维修部门。', 'Shèbèi tūrán tíngjī, qǐng jiǎnchá diànyuán shìfǒu duànkāi bìng bàogào wéixiū bùmén.', 'Thiết bị đột ngột dừng máy, hãy kiểm tra nguồn điện có bị ngắt không và báo bộ phận bảo trì.', '[{"chinese":"停机","pinyin":"tíngjī","meaning_vi":"dừng máy"},{"chinese":"电源","pinyin":"diànyuán","meaning_vi":"nguồn điện"},{"chinese":"维修部门","pinyin":"wéixiū bùmén","meaning_vi":"bộ phận bảo trì"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-f985eff4b31e09dd910c06e9.mp3', 84),
    ('运行中机器冒烟，立即按紧急停止按钮切断电源。', 'Yùnxíng zhōng jīqì màoyān, lìjí àn jǐnjí tíngzhǐ ànniǔ qiēduàn diànyuán.', 'Khi máy chạy có khói, hãy ngay lập tức nhấn nút dừng khẩn cấp và ngắt nguồn điện.', '[{"chinese":"冒烟","pinyin":"màoyān","meaning_vi":"bốc khói"},{"chinese":"紧急停止按钮","pinyin":"jǐnjí tíngzhǐ ànniǔ","meaning_vi":"nút dừng khẩn cấp"},{"chinese":"切断电源","pinyin":"qiēduàn diànyuán","meaning_vi":"cắt nguồn điện"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-d90fe7e84f5f8ab8ca7e4396.mp3', 85),
    ('现场检测到设备温度异常升高，请及时调整冷却系统。', 'Xiànchǎng jiǎncè dào shèbèi wēndù yìcháng shēnggāo, qǐng jíshí tiáozhěng lěngquè xìtǒng.', 'Tại hiện trường phát hiện nhiệt độ thiết bị tăng bất thường, hãy kịp thời điều chỉnh hệ thống làm mát.', '[{"chinese":"现场检测","pinyin":"xiànchǎng jiǎncè","meaning_vi":"kiểm tra tại hiện trường"},{"chinese":"温度异常","pinyin":"wēndù yìcháng","meaning_vi":"nhiệt độ bất thường"},{"chinese":"冷却系统","pinyin":"lěngquè xìtǒng","meaning_vi":"hệ thống làm mát"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-5d2d00fdb525cf3770ec0995.mp3', 86),
    ('发现传动轴松动，请立即紧固并排查松动原因。', 'Fāxiàn chuándòng zhóu sōngdòng, qǐng lìjí jǐngù bìng páichá sōngdòng yuányīn.', 'Phát hiện trục truyền động bị lỏng, hãy ngay lập tức siết chặt và kiểm tra nguyên nhân lỏng.', '[{"chinese":"传动轴","pinyin":"chuándòng zhóu","meaning_vi":"trục truyền động"},{"chinese":"松动","pinyin":"sōngdòng","meaning_vi":"lỏng"},{"chinese":"排查","pinyin":"páichá","meaning_vi":"kiểm tra"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-50fbeac304fd03f29e5fdf3c.mp3', 87),
    ('设备维修后需安排试运行，确认所有功能正常。', 'Shèbèi wéixiū hòu xū ānpái shì yùnxíng, quèrèn suǒyǒu gōngnéng zhèngcháng.', 'Sau khi bảo trì thiết bị cần sắp xếp chạy thử để xác nhận các chức năng đều bình thường.', '[{"chinese":"维修","pinyin":"wéixiū","meaning_vi":"bảo trì"},{"chinese":"试运行","pinyin":"shì yùnxíng","meaning_vi":"chạy thử"},{"chinese":"功能正常","pinyin":"gōngnéng zhèngcháng","meaning_vi":"chức năng bình thường"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-fa3f68260c862a06f280fe10.mp3', 88),
    ('检测发现排气系统堵塞，需要及时清理并更换滤芯。', 'Jiǎncè fāxiàn páiqì xìtǒng dǔsè, xūyào jíshí qīnglǐ bìng gēnghuàn lǜxīn.', 'Kiểm tra phát hiện hệ thống thoát khí bị tắc, cần kịp thời làm sạch và thay lọc tách.', '[{"chinese":"排气系统","pinyin":"páiqì xìtǒng","meaning_vi":"hệ thống thoát khí"},{"chinese":"堵塞","pinyin":"dǔsè","meaning_vi":"tắc"},{"chinese":"滤芯","pinyin":"lǜxīn","meaning_vi":"lọc tách"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-59e717b1997c4a7cdf322093.mp3', 89),
    ('机器连续报警，请按照故障代码手册逐项排查。', 'Jīqì liánxù bàojǐng, qǐng ànzhào gùzhàng dàimǎ shǒucè zhú xiàng páichá.', 'Máy liên tục cảnh báo, hãy theo sổ tay mã lỗi kiểm tra từng mục.', '[{"chinese":"连续报警","pinyin":"liánxù bàojǐng","meaning_vi":"cảnh báo liên tục"},{"chinese":"故障代码","pinyin":"gùzhàng dàimǎ","meaning_vi":"mã lỗi"},{"chinese":"逐项排查","pinyin":"zhú xiàng páichá","meaning_vi":"kiểm tra từng mục"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c8df6b7b78bd3139410597b7.mp3', 90),
    ('更换皮带时，请确保张紧度符合设备要求。', 'Gēnghuàn pídài shí, qǐng quèbǎo zhāngjǐn dù fúhé shèbèi yāoqiú.', 'Khi thay dây đai, hãy đảm bảo độ căng phù hợp với yêu cầu của thiết bị.', '[{"chinese":"更换","pinyin":"gēnghuàn","meaning_vi":"thay thế"},{"chinese":"皮带","pinyin":"pídài","meaning_vi":"dây đai"},{"chinese":"张紧度","pinyin":"zhāngjǐn dù","meaning_vi":"độ căng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-8ca17371f38b632f84274923.mp3', 91),
    ('维修过程中应记录所有更换零件编号和使用时间。', 'Wéixiū guòchéng zhōng yīng jìlù suǒyǒu gēnghuàn língjiàn biānhào hé shǐyòng shíjiān.', 'Trong quá trình bảo trì cần ghi lại mã số linh kiện thay thế và thời gian sử dụng.', '[{"chinese":"维修过程","pinyin":"wéixiū guòchéng","meaning_vi":"quá trình bảo trì"},{"chinese":"更换零件","pinyin":"gēnghuàn língjiàn","meaning_vi":"thay linh kiện"},{"chinese":"记录","pinyin":"jìlù","meaning_vi":"ghi chép"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-a8619ef9fd5f23e3f376fb3d.mp3', 92),
    ('发现设备运行异常振动，应立即停止生产并通知维修人员。', 'Fāxiàn shèbèi yùnxíng yìcháng zhèndòng, yīng lìjí tíngzhǐ shēngchǎn bìng tōngzhī wéixiū rényuán.', 'Phát hiện thiết bị vận hành rung động bất thường, cần ngay lập tức dừng sản xuất và báo nhân viên bảo trì.', '[{"chinese":"运行异常","pinyin":"yùnxíng yìcháng","meaning_vi":"vận hành bất thường"},{"chinese":"振动","pinyin":"zhèndòng","meaning_vi":"rung động"},{"chinese":"通知","pinyin":"tōngzhī","meaning_vi":"thông báo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-2abf43687e595ec1cd8cd120.mp3', 93),
    ('设备连续跳闸，请检查电路是否短路或接触不良。', 'Shèbèi liánxù tiàozhá, qǐng jiǎnchá diànlù shìfǒu duǎnlù huò jiēchù bùliáng.', 'Thiết bị liên tục nhảy aptomat, hãy kiểm tra mạch điện có bị chập hoặc tiếp xúc kém không.', '[{"chinese":"跳闸","pinyin":"tiàozhá","meaning_vi":"nhảy aptomat"},{"chinese":"电路","pinyin":"diànlù","meaning_vi":"mạch điện"},{"chinese":"接触不良","pinyin":"jiēchù bùliáng","meaning_vi":"tiếp xúc kém"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-0332d53bfe69cb910a42b703.mp3', 94),
    ('发现传感器异常信号，应立即停止设备并检查电缆连接。', 'Fāxiàn chuángǎnqì yìcháng xìnhào, yīng lìjí tíngzhǐ shèbèi bìng jiǎnchá diànlǎn liánjiē.', 'Phát hiện tín hiệu cảm biến bất thường, cần ngừng thiết bị ngay và kiểm tra kết nối cáp điện.', '[{"chinese":"传感器","pinyin":"chuángǎnqì","meaning_vi":"cảm biến"},{"chinese":"异常信号","pinyin":"yìcháng xìnhào","meaning_vi":"tín hiệu bất thường"},{"chinese":"电缆连接","pinyin":"diànlǎn liánjiē","meaning_vi":"kết nối cáp điện"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-0cdd7ef9f7ded83c501724f8.mp3', 95),
    ('对设备进行例行维护，清理灰尘和检查紧固件状态。', 'Duì shèbèi jìnxíng lìxíng wéihù, qīnglǐ huīchén hé jiǎnchá jǐngù jiàn zhuàngtài.', 'Thực hiện bảo trì định kỳ thiết bị, vệ sinh bụi bẩn và kiểm tra tình trạng các chi tiết siết chặt.', '[{"chinese":"例行维护","pinyin":"lìxíng wéihù","meaning_vi":"bảo trì định kỳ"},{"chinese":"紧固件","pinyin":"jǐngù jiàn","meaning_vi":"chi tiết siết chặt"},{"chinese":"清理灰尘","pinyin":"qīnglǐ huīchén","meaning_vi":"vệ sinh bụi bẩn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c87ff0d5192488080e7f04f3.mp3', 96),
    ('执行紧急停机操作时，请确认所有员工远离设备。', 'Zhíxíng jǐnjí tíngjī cāozuò shí, qǐng quèrèn suǒyǒu yuángōng yuǎnlí shèbèi.', 'Khi thực hiện thao tác dừng máy khẩn cấp, hãy xác nhận tất cả nhân viên đã rời xa thiết bị.', '[{"chinese":"紧急停机","pinyin":"jǐnjí tíngjī","meaning_vi":"dừng máy khẩn cấp"},{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"远离","pinyin":"yuǎnlí","meaning_vi":"rời xa"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-172cc26f57569804aa77fcae.mp3', 97),
    ('发现设备发热异常，请检查冷却风扇是否正常运转。', 'Fāxiàn shèbèi fārè yìcháng, qǐng jiǎnchá lěngquè fēngshàn shìfǒu zhèngcháng yùnzhuǎn.', 'Phát hiện thiết bị nóng bất thường, hãy kiểm tra quạt làm mát có vận hành bình thường không.', '[{"chinese":"发热异常","pinyin":"fārè yìcháng","meaning_vi":"nóng bất thường"},{"chinese":"冷却风扇","pinyin":"lěngquè fēngshàn","meaning_vi":"quạt làm mát"},{"chinese":"运转","pinyin":"yùnzhuǎn","meaning_vi":"vận hành"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c517ad2c5654dc53b01d79b1.mp3', 98),
    ('维修前请锁定电源开关，防止误操作引发事故。', 'Wéixiū qián qǐng suǒdìng diànyuán kāiguān, fángzhǐ wù cāozuò yǐnfā shìgù.', 'Trước khi bảo trì hãy khóa công tắc nguồn điện để tránh thao tác nhầm gây ra tai nạn.', '[{"chinese":"锁定","pinyin":"suǒdìng","meaning_vi":"khóa"},{"chinese":"误操作","pinyin":"wù cāozuò","meaning_vi":"thao tác nhầm"},{"chinese":"事故","pinyin":"shìgù","meaning_vi":"tai nạn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-e5c2abf681be9fc8fa34b93b.mp3', 99),
    ('设备启动后，请确认报警灯是否正常熄灭。', 'Shèbèi qǐdòng hòu, qǐng quèrèn bàojǐng dēng shìfǒu zhèngcháng xīmiè.', 'Sau khi thiết bị khởi động, hãy xác nhận đèn cảnh báo đã tắt bình thường chưa.', '[{"chinese":"启动","pinyin":"qǐdòng","meaning_vi":"khởi động"},{"chinese":"报警灯","pinyin":"bàojǐng dēng","meaning_vi":"đèn cảnh báo"},{"chinese":"熄灭","pinyin":"xīmiè","meaning_vi":"tắt"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-ad203b80d3eea9d100a5a5d9.mp3', 100),
    ('操作机械时必须穿戴防护服，防止油污和划伤。', 'Cāozuò jīxiè shí bìxū chuāndài fánghùfú, fángzhǐ yóuwū hé huáshāng.', 'Khi vận hành máy móc phải mặc đồ bảo hộ để ngăn dầu mỡ và trầy xước.', '[{"chinese":"防护服","pinyin":"fánghùfú","meaning_vi":"đồ bảo hộ"},{"chinese":"操作","pinyin":"cāozuò","meaning_vi":"vận hành, thao tác"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-16f02e97f6c4c9cde5b46827.mp3', 101),
    ('进入车间请戴好安全帽和防护眼镜，避免飞溅伤害。', 'Jìnrù chējiān qǐng dài hǎo ānquánmào hé fánghù yǎnjìng, bìmiǎn fēijiàn shānghài.', 'Vào xưởng phải đội mũ bảo hộ và đeo kính bảo hộ để tránh bị văng trầy xước.', '[{"chinese":"防护眼镜","pinyin":"fánghù yǎnjìng","meaning_vi":"kính bảo hộ"},{"chinese":"安全帽","pinyin":"ānquánmào","meaning_vi":"mũ bảo hộ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-b442c1fdd4447fd68bb000c8.mp3', 102),
    ('设备维修前须先切断电源并严格执行锁定程序。', 'Shèbèi wéixiū qián xū xiān qiēduàn diànyuán bìng yángé zhíxíng suǒdìng chéngxù.', 'Trước khi bảo trì thiết bị phải khóa nguồn điện và thực hiện đúng quy trình khóa an toàn.', '[{"chinese":"切断","pinyin":"qiēduàn","meaning_vi":"cắt, ngắt"},{"chinese":"锁定","pinyin":"suǒdìng","meaning_vi":"khóa (nguồn)"},{"chinese":"执行","pinyin":"zhíxíng","meaning_vi":"thực hiện"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-3aa9e0ac0e1702ab30b556fe.mp3', 103),
    ('未经许可不得拆卸机械保护罩，防止意外伤害发生。', 'Wèijīng xǔkě bùdé chāixiè jīxiè bǎohù zhào, fángzhǐ yìwài shānghài fāshēng.', 'Chưa được phép không được tháo tấm chắn máy để tránh tai nạn xảy ra.', '[{"chinese":"拆卸","pinyin":"chāixiè","meaning_vi":"tháo dỡ"},{"chinese":"保护罩","pinyin":"bǎohù zhào","meaning_vi":"tấm chắn bảo hộ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-8bed3ea8b2c42dd34a6fc985.mp3', 104),
    ('车间入口处设有明显的安全警示标志，请勿随意进入。', 'Chējiān rùkǒu chù shè yǒu míngxiǎn de ānquán jǐngshì biāozhì, qǐng wù suíyì jìnrù.', 'Lối vào xưởng có biển cảnh báo an toàn rõ ràng, xin đừng vào bừa bãi.', '[{"chinese":"安全警示","pinyin":"ānquán jǐngshì","meaning_vi":"cảnh báo an toàn"},{"chinese":"标志","pinyin":"biāozhì","meaning_vi":"biển báo, dấu hiệu"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-276eab31d75798d69e808b02.mp3', 105),
    ('使用化学品时必须穿戴防护手套，防止皮肤接触。', 'Shǐyòng huàxué pǐn shí bìxū chuāndài fánghù shǒutào, fángzhǐ pífū jiēchù.', 'Khi sử dụng hóa chất phải đeo găng tay bảo hộ để tránh da tiếp xúc trực tiếp.', '[{"chinese":"化学品","pinyin":"huàxué pǐn","meaning_vi":"hóa chất"},{"chinese":"防护手套","pinyin":"fánghù shǒutào","meaning_vi":"găng tay bảo hộ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-1d4df21fd1b2f690c57a7c61.mp3', 106),
    ('搬运重物时请使用吊装设备，避免人力直接抬举造成损伤。', 'Bānyùn zhòngwù shí qǐng shǐyòng diàozhuāng shèbèi, bìmiǎn rénlì zhíjiē táijǔ zàochéng sǔnshāng.', 'Khi nâng hàng nặng hãy dùng thiết bị nâng hạ, tránh nâng trực tiếp bằng sức người gây tổn thương.', '[{"chinese":"吊装设备","pinyin":"diàozhuāng shèbèi","meaning_vi":"thiết bị nâng hạ"},{"chinese":"搬运","pinyin":"bānyùn","meaning_vi":"vận chuyển, di chuyển"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-0fda33c4664579d11a2fbdff.mp3', 107),
    ('车间内禁止堵塞紧急出口，确保疏散通道畅通无阻。', 'Chējiān nèi jìnzhǐ dǔsè jǐnjí chūkǒu, quèbǎo shūsàn tōngdào chàngtōng wúzǔ.', 'Bên trong xưởng cấm chắn lối thoát hiểm để đảm bảo lối đi thông thoáng khi di tản.', '[{"chinese":"堵塞","pinyin":"dǔsè","meaning_vi":"chặn, chắn"},{"chinese":"紧急出口","pinyin":"jǐnjí chūkǒu","meaning_vi":"lối thoát hiểm"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-ca80602420e5919e94f0f0f6.mp3', 108),
    ('发现安全事故应立即报告主管部门并采取应急措施。', 'Fāxiàn ānquán shìgù yīng lìjí bàogào zhǔguǎn bùmén bìng cǎiqǔ yìngjí cuòshī.', 'Phát hiện sự cố an toàn phải báo ngay cho bộ phận phụ trách và thực hiện biện pháp khẩn cấp.', '[{"chinese":"安全事故","pinyin":"ānquán shìgù","meaning_vi":"sự cố an toàn"},{"chinese":"应急措施","pinyin":"yìngjí cuòshī","meaning_vi":"biện pháp ứng phó khẩn cấp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-5e1cbc37ad0bf406e6bf3ccd.mp3', 109),
    ('发生工伤后，应立即进行现场急救并通知医疗人员。', 'Fāshēng gōngshāng hòu, yīng lìjí jìnxíng xiànchǎng jíjiù bìng tōngzhī yīliáo rényuán.', 'Khi xảy ra tai nạn lao động phải cấp cứu ngay tại chỗ và báo y tế.', '[{"chinese":"工伤","pinyin":"gōngshāng","meaning_vi":"tai nạn lao động"},{"chinese":"急救","pinyin":"jíjiù","meaning_vi":"cấp cứu"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-a70295840332965b75c1d34b.mp3', 110),
    ('操作车间设备前必须确认所有安全防护装置已开启。', 'Cāozuò chējiān shèbèi qián bìxū quèrèn suǒyǒu ānquán fánghù zhuāngzhì yǐ kāiqǐ.', 'Trước khi vận hành thiết bị trong xưởng phải xác nhận tất cả thiết bị bảo hộ đã bật hoạt động.', '[{"chinese":"防护装置","pinyin":"fánghù zhuāngzhì","meaning_vi":"thiết bị bảo hộ"},{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-a570e01cbe8c2552357ba806.mp3', 111),
    ('禁止在生产区域内吸烟，防止火灾和爆炸危险。', 'Jìnzhǐ zài shēngchǎn qūyù nèi xīyān, fángzhǐ huǒzāi hé bàozhà wēixiǎn.', 'Cấm hút thuốc trong khu vực sản xuất để phòng cháy nổ và nguy hiểm cháy nổ.', '[{"chinese":"禁止","pinyin":"jìnzhǐ","meaning_vi":"cấm"},{"chinese":"火灾","pinyin":"huǒzāi","meaning_vi":"cháy"},{"chinese":"爆炸","pinyin":"bàozhà","meaning_vi":"nổ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-eb30436fb45b44fc174f0e2a.mp3', 112),
    ('操作高温设备时，必须穿戴隔热手套和防护面罩。', 'Cāozuò gāowēn shèbèi shí, bìxū chuāndài gérè shǒutào hé fánghù miànzhào.', 'Khi vận hành thiết bị nhiệt độ cao phải đeo găng tay cách nhiệt và mặt nạ bảo hộ.', '[{"chinese":"隔热手套","pinyin":"gérè shǒutào","meaning_vi":"găng tay cách nhiệt"},{"chinese":"防护面罩","pinyin":"fánghù miànzhào","meaning_vi":"mặt nạ bảo hộ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-1599659fb351c53afc6f106f.mp3', 113),
    ('搬运重物时应使用吊带，避免手部受伤和物品滑落。', 'Bānyùn zhòngwù shí yīng shǐyòng diàodài, bìmiǎn shǒubù shòushāng hé wùpǐn huáluò.', 'Khi nâng vật nặng nên dùng dây đai nâng để tránh tổn thương tay và hàng hóa bị rơi.', '[{"chinese":"吊带","pinyin":"diàodài","meaning_vi":"dây đai nâng"},{"chinese":"滑落","pinyin":"huáluò","meaning_vi":"trượt rơi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-39ceaa37a31cab84f6f9f482.mp3', 114),
    ('确保紧急出口畅通无阻，发生火灾时迅速疏散人员。', 'Quèbǎo jǐnjí chūkǒu chàngtōng wúzǔ, fāshēng huǒzāi shí xùnsù shūsàn rényuán.', 'Đảm bảo lối thoát hiểm luôn thông suốt để kịp thời sơ tán khi có cháy.', '[{"chinese":"紧急出口","pinyin":"jǐnjí chūkǒu","meaning_vi":"lối thoát hiểm"},{"chinese":"疏散","pinyin":"shūsàn","meaning_vi":"sơ tán"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-bebc2428ecf1b2691d3df2dc.mp3', 115),
    ('发现工伤事故应立即停止作业并报告安全管理人员。', 'Fāxiàn gōngshāng shìgù yīng lìjí tíngzhǐ zuòyè bìng bàogào ānquán guǎnlǐ rényuán.', 'Phát hiện tai nạn lao động phải ngay lập tức ngừng công việc và báo cho nhân viên an toàn.', '[{"chinese":"停止","pinyin":"tíngzhǐ","meaning_vi":"dừng, ngừng"},{"chinese":"报告","pinyin":"bàogào","meaning_vi":"báo cáo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c14a5d67dd41184cccea426c.mp3', 116),
    ('储存化学品必须遵守安全规程，保持通风和标识清楚。', 'Chúcún huàxué pǐn bìxū zūnshǒu ānquán guīchéng, bǎochí tōngfēng hé biāoshí qīngchǔ.', 'Lưu trữ hóa chất phải tuân thủ quy định an toàn, giữ thông thoáng và dán nhãn rõ ràng.', '[{"chinese":"遵守","pinyin":"zūnshǒu","meaning_vi":"tuân thủ"},{"chinese":"通风","pinyin":"tōngfēng","meaning_vi":"thông gió"},{"chinese":"标识","pinyin":"biāoshí","meaning_vi":"dán nhãn, đánh dấu"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-32a977165d07e5fa6d2de711.mp3', 117),
    ('请佩戴防尘口罩，防止粉尘进入呼吸道引发疾病。', 'Qǐng pèidài fángchén kǒuzhào, fángzhǐ fěnchén jìnrù hūxīdào yǐnfā jíbìng.', 'Hãy đeo khẩu trang chống bụi để ngăn bụi xâm nhập đường hô hấp gây bệnh.', '[{"chinese":"防尘口罩","pinyin":"fángchén kǒuzhào","meaning_vi":"khẩu trang chống bụi"},{"chinese":"呼吸道","pinyin":"hūxīdào","meaning_vi":"đường hô hấp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-b825ff34aa5e3281b107a75f.mp3', 118),
    ('核实设备电源是否已锁定，防止维修过程中误操作。', 'Héshí shèbèi diànyuán shìfǒu yǐ suǒdìng, fángzhǐ wéixiū guòchéng zhōng wù cāozuò.', 'Kiểm tra nguồn điện thiết bị đã được khóa chưa để tránh thao tác sai trong quá trình sửa chữa.', '[{"chinese":"核实","pinyin":"héshí","meaning_vi":"kiểm tra, xác minh"},{"chinese":"误操作","pinyin":"wù cāozuò","meaning_vi":"thao tác sai"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-585caef7c7d7d3511348d788.mp3', 119),
    ('存放易燃物品应远离热源并设置明显警告标识。', 'Cúnfàng yìrán wùpǐn yīng yuǎnlí rèyuán bìng shèzhì míngxiǎn jǐnggào biāoshí.', 'Bảo quản vật dễ cháy phải đặt xa nguồn nhiệt và dán biển cảnh báo rõ ràng.', '[{"chinese":"易燃","pinyin":"yìrán","meaning_vi":"dễ cháy"},{"chinese":"警告标识","pinyin":"jǐnggào biāoshí","meaning_vi":"biển cảnh báo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-7b8c35ab226041efa3f9f70d.mp3', 120),
    ('机器运行时禁止打开安全门，确保操作人员安全。', 'Jīqì yùnxíng shí jìnzhǐ dǎkāi ānquánmén, quèbǎo cāozuò rényuán ānquán.', 'Máy đang vận hành không được mở cửa bảo hộ để đảm bảo an toàn cho người vận hành.', '[{"chinese":"安全门","pinyin":"ānquánmén","meaning_vi":"cửa an toàn"},{"chinese":"操作人员","pinyin":"cāozuò rényuán","meaning_vi":"người vận hành"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-453cb90462301671ebde0c44.mp3', 121),
    ('使用电动工具时请确认接地良好，防止触电事故。', 'Shǐyòng diàndòng gōngjù shí qǐng quèrèn jiēdì liánghǎo, fángzhǐ chùdiàn shìgù.', 'Khi dùng dụng cụ điện phải xác nhận tiếp đất tốt để ngừa tai nạn điện giật.', '[{"chinese":"电动工具","pinyin":"diàndòng gōngjù","meaning_vi":"dụng cụ điện"},{"chinese":"接地","pinyin":"jiēdì","meaning_vi":"tiếp đất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-a176ee222942906439411590.mp3', 122),
    ('设备出现异常声音，应立即停止运行并排查故障原因。', 'Shèbèi chūxiàn yìcháng shēngyīn, yīng lìjí tíngzhǐ yùnxíng bìng páichá gùzhàng yuányīn.', 'Thiết bị phát ra tiếng lạ phải dừng hoạt động ngay và kiểm tra nguyên nhân hư hỏng.', '[{"chinese":"异常声音","pinyin":"yìcháng shēngyīn","meaning_vi":"tiếng bất thường"},{"chinese":"排查","pinyin":"páichá","meaning_vi":"kiểm tra, rà soát"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-59826a1f011bd9f7da05efb0.mp3', 123),
    ('提升重物时应确认吊车承重能力，防止事故发生。', 'Tíshēng zhòngwù shí yīng quèrèn diàochē chéngzhòng nénglì, fángzhǐ shìgù fāshēng.', 'Khi nâng vật nặng phải xác nhận tải trọng của cần cẩu để ngừa tai nạn.', '[{"chinese":"提升","pinyin":"tíshēng","meaning_vi":"nâng lên"},{"chinese":"承重能力","pinyin":"chéngzhòng nénglì","meaning_vi":"khả năng chịu trọng tải"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-86a83b47fffc5f25252c65e6.mp3', 124),
    ('生产现场请保持地面干净整洁，防止滑倒和跌落事故。', 'Shēngchǎn xiànchǎng qǐng bǎochí dìmiàn gānjìng zhěngjié, fángzhǐ huádǎo hé diēluò shìgù.', 'Nơi sản xuất phải giữ sàn nhà sạch sẽ, tránh tai nạn trượt ngã và rơi rớt.', '[{"chinese":"滑倒","pinyin":"huádǎo","meaning_vi":"trượt ngã"},{"chinese":"跌落","pinyin":"diēluò","meaning_vi":"rơi ngã"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-d5551b4991cd52581c193f46.mp3', 125),
    ('请确认本周的生产计划和订单数量是否一致。', 'Qǐng quèrèn běn zhōu de shēngchǎn jìhuà hé dìngdān shùliàng shìfǒu yīzhì.', 'Vui lòng xác nhận kế hoạch sản xuất tuần này có khớp với số lượng đơn hàng không.', '[{"chinese":"生产计划","pinyin":"shēngchǎn jìhuà","meaning_vi":"kế hoạch sản xuất"},{"chinese":"订单","pinyin":"dìngdān","meaning_vi":"đơn hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-71ca9e036b14d7963deeefa0.mp3', 126),
    ('请调整今天的生产人员安排，确保效率最大化。', 'Qǐng tiáozhěng jīntiān de shēngchǎn rényuán ānpái, quèbǎo xiàolǜ zuìdàhuà.', 'Vui lòng điều chỉnh bố trí nhân sự sản xuất hôm nay, đảm bảo hiệu quả tối đa.', '[{"chinese":"调整","pinyin":"tiáozhěng","meaning_vi":"điều chỉnh"},{"chinese":"生产人员","pinyin":"shēngchǎn rényuán","meaning_vi":"nhân sự sản xuất"},{"chinese":"效率","pinyin":"xiàolǜ","meaning_vi":"hiệu suất, hiệu quả"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-a177d4d1df5137e5e45d72d1.mp3', 127),
    ('目前生产进度滞后，请报告具体原因和解决方案。', 'Mùqián shēngchǎn jìndù zhìhòu, qǐng bàogào jùtǐ yuányīn hé jiějué fāng''àn.', 'Hiện tiến độ sản xuất đang chậm, xin báo cáo nguyên nhân cụ thể và phương án giải quyết.', '[{"chinese":"生产进度","pinyin":"shēngchǎn jìndù","meaning_vi":"tiến độ sản xuất"},{"chinese":"滞后","pinyin":"zhìhòu","meaning_vi":"chậm trễ"},{"chinese":"解决方案","pinyin":"jiějué fāng''àn","meaning_vi":"phương án giải quyết"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-b34762ce40e3476ec640e842.mp3', 128),
    ('接收到的订单已确认，预计明天开始生产。', 'Jiēshōu dào de dìngdān yǐ quèrèn, yùjì míngtiān kāishǐ shēngchǎn.', 'Đơn hàng nhận được đã được xác nhận, dự kiến bắt đầu sản xuất từ ngày mai.', '[{"chinese":"订单","pinyin":"dìngdān","meaning_vi":"đơn hàng"},{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"生产","pinyin":"shēngchǎn","meaning_vi":"sản xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-d5d10896ca28f67686facdc4.mp3', 129),
    ('请报告昨天完成的产品数量和合格率。', 'Qǐng bàogào zuótiān wánchéng de chǎnpǐn shùliàng hé hégé lǜ.', 'Vui lòng báo cáo số lượng sản phẩm hoàn thành và tỷ lệ đạt chuẩn của ngày hôm qua.', '[{"chinese":"产品数量","pinyin":"chǎnpǐn shùliàng","meaning_vi":"số lượng sản phẩm"},{"chinese":"合格率","pinyin":"hégé lǜ","meaning_vi":"tỷ lệ đạt chuẩn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-f16329e117e41d4b769d8308.mp3', 130),
    ('请配合质检部门，做好成品的最终包装和标识。', 'Qǐng pèihé zhìjiǎn bùmén, zuò hǎo chéngpǐn de zuìzhōng bāozhuāng hé biāoshí.', 'Vui lòng phối hợp bộ phận chất lượng kiểm tra, hoàn thiện việc đóng gói và ghi nhãn thành phẩm cuối cùng.', '[{"chinese":"配合","pinyin":"pèihé","meaning_vi":"phối hợp"},{"chinese":"质检部门","pinyin":"zhìjiǎn bùmén","meaning_vi":"bộ phận chất lượng"},{"chinese":"成品","pinyin":"chéngpǐn","meaning_vi":"thành phẩm"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-3fb4decf61b37b175e31daaa.mp3', 131),
    ('请提前准备好运输车辆，确保按时发货。', 'Qǐng tíqián zhǔnbèi hǎo yùnshū chēliàng, quèbǎo ànshí fāhuò.', 'Xin chuẩn bị trước xe vận chuyển, đảm bảo giao hàng đúng thời gian.', '[{"chinese":"提前","pinyin":"tíqián","meaning_vi":"trước thời hạn, trước"},{"chinese":"运输车辆","pinyin":"yùnshū chēliàng","meaning_vi":"xe vận chuyển"},{"chinese":"发货","pinyin":"fāhuò","meaning_vi":"giao hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-724202f0affdbe3c7a1491c7.mp3', 132),
    ('请检查原材料的到货时间，避免影响生产计划。', 'Qǐng jiǎnchá yuáncáiliào de dàohuò shíjiān, bìmiǎn yǐngxiǎng shēngchǎn jìhuà.', 'Vui lòng kiểm tra thời gian nguyên liệu về để tránh ảnh hưởng kế hoạch sản xuất.', '[{"chinese":"原材料","pinyin":"yuáncáiliào","meaning_vi":"nguyên liệu"},{"chinese":"到货时间","pinyin":"dàohuò shíjiān","meaning_vi":"thời gian nhận hàng"},{"chinese":"生产计划","pinyin":"shēngchǎn jìhuà","meaning_vi":"kế hoạch sản xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-bde60af92dcbf3b2139019f3.mp3', 133),
    ('订单确认后，请及时安排生产线启动。', 'Dìngdān quèrèn hòu, qǐng jíshí ānpái shēngchǎnxiàn qǐdòng.', 'Sau khi xác nhận đơn hàng, hãy sắp xếp khởi động dây chuyền sản xuất kịp thời.', '[{"chinese":"订单确认","pinyin":"dìngdān quèrèn","meaning_vi":"xác nhận đơn hàng"},{"chinese":"安排","pinyin":"ānpái","meaning_vi":"sắp xếp"},{"chinese":"生产线","pinyin":"shēngchǎnxiàn","meaning_vi":"dây chuyền sản xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-cf8ae5d743f53505c5d4dc61.mp3', 134),
    ('发现原材料短缺，请立即通知采购部门补货。', 'Fāxiàn yuáncáiliào duǎnquē, qǐng lìjí tōngzhī cǎigòu bùmén bǔ huò.', 'Phát hiện thiếu nguyên liệu, xin lập tức báo cho bộ phận mua hàng bổ sung.', '[{"chinese":"原材料","pinyin":"yuáncáiliào","meaning_vi":"nguyên liệu"},{"chinese":"短缺","pinyin":"duǎnquē","meaning_vi":"thiếu hụt"},{"chinese":"采购部门","pinyin":"cǎigòu bùmén","meaning_vi":"bộ phận mua hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-6d7b10e5fbce4a118cc88714.mp3', 135),
    ('请根据订单调整生产计划，合理分配人力资源。', 'Qǐng gēnjù dìngdān tiáozhěng shēngchǎn jìhuà, hélǐ fēnpèi rénlì zīyuán.', 'Vui lòng điều chỉnh kế hoạch sản xuất theo đơn hàng, phân bổ nguồn nhân lực hợp lý.', '[{"chinese":"订单","pinyin":"dìngdān","meaning_vi":"đơn hàng"},{"chinese":"生产计划","pinyin":"shēngchǎn jìhuà","meaning_vi":"kế hoạch sản xuất"},{"chinese":"分配","pinyin":"fēnpèi","meaning_vi":"phân bổ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-f1742254f9f49245af672f2e.mp3', 136),
    ('本班完成产品总量为八千个，符合生产指标。', 'Běn bān wánchéng chǎnpǐn zǒngliàng wèi bā qiān gè, fúhé shēngchǎn zhǐbiāo.', 'Ca này hoàn thành tổng cộng tám nghìn sản phẩm, đạt chỉ tiêu sản xuất.', '[{"chinese":"完成","pinyin":"wánchéng","meaning_vi":"hoàn thành"},{"chinese":"产品总量","pinyin":"chǎnpǐn zǒngliàng","meaning_vi":"tổng lượng sản phẩm"},{"chinese":"生产指标","pinyin":"shēngchǎn zhǐbiāo","meaning_vi":"chỉ tiêu sản xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-c2a7d22dd3a64c107b35351f.mp3', 137),
    ('接收订单后，请立刻安排物流部门发货。', 'Jiēshōu dìngdān hòu, qǐng lìkè ānpái wùliú bùmén fāhuò.', 'Sau khi nhận đơn hàng, vui lòng sắp xếp bộ phận logistics giao hàng ngay lập tức.', '[{"chinese":"接收","pinyin":"jiēshōu","meaning_vi":"nhận"},{"chinese":"物流部门","pinyin":"wùliú bùmén","meaning_vi":"bộ phận logistics"},{"chinese":"发货","pinyin":"fāhuò","meaning_vi":"giao hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-a931a0e02bdd95df719c7824.mp3', 138),
    ('请每天记录生产数量及异常情况，方便后续追踪。', 'Qǐng měitiān jìlù shēngchǎn shùliàng jí yìcháng qíngkuàng, fāngbiàn hòuxù zhuīzōng.', 'Vui lòng ghi chép số lượng sản xuất và tình trạng bất thường hàng ngày để thuận tiện theo dõi sau này.', '[{"chinese":"记录","pinyin":"jìlù","meaning_vi":"ghi chép"},{"chinese":"异常情况","pinyin":"yìcháng qíngkuàng","meaning_vi":"tình trạng bất thường"},{"chinese":"后续","pinyin":"hòuxù","meaning_vi":"tiếp theo, sau này"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-f18bd2092cc0e81d2197ed35.mp3', 139),
    ('生产线缺少操作人员，请立即调整排班表。', 'Shēngchǎn xiàn quēshǎo cāozuò rényuán, qǐng lìjí tiáozhěng páibān biǎo.', 'Dây chuyền sản xuất thiếu nhân viên vận hành, hãy điều chỉnh bảng phân ca ngay lập tức.', '[{"chinese":"生产线","pinyin":"shēngchǎn xiàn","meaning_vi":"dây chuyền sản xuất"},{"chinese":"操作人员","pinyin":"cāozuò rényuán","meaning_vi":"nhân viên vận hành"},{"chinese":"调整","pinyin":"tiáozhěng","meaning_vi":"điều chỉnh"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-d9295a820cc15452b3931ba2.mp3', 140),
    ('请完成当天生产任务后，及时汇报产量情况。', 'Qǐng wánchéng dāngtiān shēngchǎn rènwù hòu, jíshí huìbào chǎnliàng qíngkuàng.', 'Sau khi hoàn thành nhiệm vụ sản xuất trong ngày, vui lòng báo cáo sản lượng kịp thời.', '[{"chinese":"生产任务","pinyin":"shēngchǎn rènwù","meaning_vi":"nhiệm vụ sản xuất"},{"chinese":"及时","pinyin":"jíshí","meaning_vi":"kịp thời"},{"chinese":"汇报","pinyin":"huìbào","meaning_vi":"báo cáo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-4c4e6dead42128b4ad4921aa.mp3', 141),
    ('请核对订单规格，确认生产原材料的品种和数量。', 'Qǐng héduì dìngdān guīgé, quèrèn shēngchǎn yuáncáiliào de pǐnzhǒng hé shùliàng.', 'Xin kiểm tra quy cách đơn hàng, xác nhận chủng loại và số lượng nguyên liệu sản xuất.', '[{"chinese":"核对","pinyin":"héduì","meaning_vi":"đối chiếu, kiểm tra"},{"chinese":"订单规格","pinyin":"dìngdān guīgé","meaning_vi":"quy cách đơn hàng"},{"chinese":"原材料","pinyin":"yuáncáiliào","meaning_vi":"nguyên liệu"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-f5bb0ba34737e8bd8578eefe.mp3', 142),
    ('发现包装材料不足，请提前通知采购部门补充。', 'Fāxiàn bāozhuāng cáiliào bùzú, qǐng tíqián tōngzhī cǎigòu bùmén bǔchōng.', 'Phát hiện vật liệu đóng gói không đủ, vui lòng báo bộ phận mua hàng bổ sung trước.', '[{"chinese":"包装材料","pinyin":"bāozhuāng cáiliào","meaning_vi":"vật liệu đóng gói"},{"chinese":"不足","pinyin":"bùzú","meaning_vi":"không đủ"},{"chinese":"采购部门","pinyin":"cǎigòu bùmén","meaning_vi":"bộ phận mua hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-d1bb32cf96110eebebea06dc.mp3', 143),
    ('请确认所有生产设备已准备就绪，确保开工顺利。', 'Qǐng quèrèn suǒyǒu shēngchǎn shèbèi yǐ zhǔnbèi jiùxù, quèbǎo kāigōng shùnlì.', 'Vui lòng xác nhận tất cả thiết bị sản xuất đã chuẩn bị sẵn sàng, đảm bảo khởi công thuận lợi.', '[{"chinese":"生产设备","pinyin":"shēngchǎn shèbèi","meaning_vi":"thiết bị sản xuất"},{"chinese":"准备就绪","pinyin":"zhǔnbèi jiùxù","meaning_vi":"chuẩn bị xong"},{"chinese":"开工","pinyin":"kāigōng","meaning_vi":"khởi công, bắt đầu sản xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-65350f6e6d65c6100ac7b2e9.mp3', 144),
    ('请按照生产计划，合理安排包装和装箱工作。', 'Qǐng ànzhào shēngchǎn jìhuà, hélǐ ānpái bāozhuāng hé zhuāngxiāng gōngzuò.', 'Vui lòng theo kế hoạch sản xuất, sắp xếp hợp lý công việc đóng gói và xếp thùng.', '[{"chinese":"生产计划","pinyin":"shēngchǎn jìhuà","meaning_vi":"kế hoạch sản xuất"},{"chinese":"包装","pinyin":"bāozhuāng","meaning_vi":"đóng gói"},{"chinese":"装箱","pinyin":"zhuāngxiāng","meaning_vi":"xếp thùng, đóng thùng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-6d904a7fdf2e9c6ee86c4242.mp3', 145),
    ('请确认本班所有人员已了解今天的生产任务。', 'Qǐng quèrèn běn bān suǒyǒu rényuán yǐ liǎojiě jīntiān de shēngchǎn rènwù.', 'Xin xác nhận tất cả thành viên ca này đã hiểu nhiệm vụ sản xuất hôm nay.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"生产任务","pinyin":"shēngchǎn rènwù","meaning_vi":"nhiệm vụ sản xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-f08bd51fd110927c2462cd1f.mp3', 146),
    ('请报告原材料入库时间，方便生产线安排。', 'Qǐng bàogào yuáncáiliào rùkù shíjiān, fāngbiàn shēngchǎnxiàn ānpái.', 'Vui lòng báo cáo thời gian nhập kho nguyên liệu để tiện sắp xếp dây chuyền sản xuất.', '[{"chinese":"原材料","pinyin":"yuáncáiliào","meaning_vi":"nguyên liệu"},{"chinese":"入库","pinyin":"rùkù","meaning_vi":"nhập kho"},{"chinese":"生产线","pinyin":"shēngchǎnxiàn","meaning_vi":"dây chuyền sản xuất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-1aec1b13ce28f78daa5803e3.mp3', 147),
    ('如遇生产异常情况，请及时联系相关部门处理。', 'Rú yù shēngchǎn yìcháng qíngkuàng, qǐng jíshí liánxì xiāngguān bùmén chǔlǐ.', 'Nếu gặp tình trạng bất thường trong sản xuất, vui lòng liên hệ bộ phận liên quan xử lý kịp thời.', '[{"chinese":"生产异常","pinyin":"shēngchǎn yìcháng","meaning_vi":"bất thường trong sản xuất"},{"chinese":"及时","pinyin":"jíshí","meaning_vi":"kịp thời"},{"chinese":"相关部门","pinyin":"xiāngguān bùmén","meaning_vi":"bộ phận liên quan"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-93b550de1bfb64d5492cb178.mp3', 148),
    ('请确认产品包装尺寸符合客户要求后再发货。', 'Qǐng quèrèn chǎnpǐn bāozhuāng chǐcùn fúhé kèhù yāoqiú hòu zài fāhuò.', 'Hãy xác nhận kích thước đóng gói sản phẩm đúng yêu cầu khách hàng rồi mới giao hàng.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"产品包装","pinyin":"chǎnpǐn bāozhuāng","meaning_vi":"đóng gói sản phẩm"},{"chinese":"客户要求","pinyin":"kèhù yāoqiú","meaning_vi":"yêu cầu khách hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-0847db80978135226fe710f6.mp3', 149),
    ('今天接到新的生产计划，需要立即确认订单详情。', 'Jīntiān jiē dào xīn de shēngchǎn jìhuà, xūyào lìjí quèrèn dìngdān xiángqíng.', 'Hôm nay nhận kế hoạch sản xuất mới, cần xác nhận ngay chi tiết đơn hàng.', '[{"chinese":"生产计划","pinyin":"shēngchǎn jìhuà","meaning_vi":"kế hoạch sản xuất"},{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"订单","pinyin":"dìngdān","meaning_vi":"đơn hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-150-cau/sentence-7e50d28aceb3f31947ffd219.mp3', 150)
) as card(
  sentence_cn, sentence_pinyin, sentence_vi,
